<script setup lang="ts">
import { ref, onMounted } from 'vue'
import { useRouter } from 'vue-router'
import { SyncManager } from '@/sync/SyncManager'
import { Button } from 'frappe-ui'

const router = useRouter()
const status = ref('Initializing...')
const progress = ref(0)
const error = ref('')

onMounted(async () => {
  try {
    await SyncManager.fullInitialSync((newStatus, percent) => {
      status.value = newStatus
      progress.value = percent
    })
    
    setTimeout(() => {
      router.push('/login-pin')
    }, 1000)
    
  } catch (err: any) {
    error.value = err.message || 'Sync failed.'
  }
})
</script>

<template>
  <div class="flex h-screen flex-col items-center justify-center bg-gray-50 dark:bg-gray-900">
    <div class="w-full max-w-md rounded-xl bg-white p-8 shadow-xl dark:bg-gray-800 text-center">
      <h1 class="text-2xl font-bold text-gray-900 dark:text-white mb-6">Initial Synchronization</h1>
      
      <div v-if="error" class="text-red-500 mb-4">
        {{ error }}
      </div>
      
      <div v-else>
        <div class="mb-2 text-sm text-gray-600 dark:text-gray-400 font-medium">
          {{ status }}
        </div>
        
        <div class="w-full bg-gray-200 rounded-full h-2.5 dark:bg-gray-700 mb-6 overflow-hidden">
          <div class="bg-blue-600 h-2.5 rounded-full transition-all duration-300" :style="`width: ${progress}%`"></div>
        </div>
        
        <p class="text-xs text-gray-500">Please do not close the app. This may take a few minutes depending on your internet connection.</p>
      </div>
      
      <Button v-if="error" class="mt-6" @click="router.push('/setup')">Back to Setup</Button>
    </div>
  </div>
</template>
